// Validation JWT & extraction tenant_id
const input = $input.first().json;
const headers = input.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';

if (!authHeader.startsWith('Bearer ')) {
  return [{ json: { _error: true, _error_code: 'UNAUTHORIZED', _error_message: 'JWT requis' } }];
}

const token = authHeader.split(' ')[1];
const parts = token.split('.');
if (parts.length < 2) {
  return [{ json: { _error: true, _error_code: 'INVALID_JWT', _error_message: 'JWT invalide' } }];
}

let payload;
try {
  payload = JSON.parse(Buffer.from(parts[1], 'base64').toString());
} catch (e) {
  return [{ json: { _error: true, _error_code: 'INVALID_JWT_PAYLOAD', _error_message: 'Payload JWT invalide' } }];
}

const tenant_id = payload.tenant_id || payload.sub;
if (!tenant_id) {
  return [{ json: { _error: true, _error_code: 'MISSING_TENANT', _error_message: 'tenant_id absent du JWT' } }];
}

return [{ json: { ...input, _tenant_id: String(tenant_id), _jwt_valid: true } }];

// ============================================================
// OrchestratorAgent v4 — Initialisation
// ============================================================
// Le tenant_id est injecté par le nœud JWT précédent.
// ============================================================

const input = $input.first().json;
let batch;
if (Array.isArray(input.body?.batch)) batch = input.body.batch;
else if (Array.isArray(input.body?.payload?.batch)) batch = input.body.payload.batch;
else if (Array.isArray(input.body)) batch = input.body;
else if (Array.isArray(input.batch)) batch = input.batch;
else if (Array.isArray(input.payload?.batch)) batch = input.payload.batch;
else batch = null;

if (!batch || batch.length === 0) {
  return [{ json: { _error: true, _error_code: 'EMPTY_OR_MISSING_BATCH', _error_message: 'Batch absent ou vide' } }];
}

if (!input._tenant_id) {
  return [{ json: { _error: true, _error_code: 'MISSING_TENANT', _error_message: 'tenant_id introuvable après validation JWT' } }];
}

const now = new Date();
const hex = Array.from({ length: 6 }, () =>
  Math.floor(Math.random() * 16).toString(16).toUpperCase()
).join('');

return [{
  json: {
    _error: false,
    _tenant_id: input._tenant_id,
    _jwt_valid: true,
    correlation_id: `ORCH-${now.getFullYear()}-${hex}`,
    source_agent_header: input.headers?.['x-source-agent'] || input.body?.source_agent || 'UNKNOWN',
    batch,
    batch_size: batch.length,
    timestamp: now.toISOString(),
  }
}];

// ============================================================
// v4 — Préparer le batch pour enqueue dans Redis
// ============================================================

const init = $input.first().json;
const batch = init.batch;
const correlation_id = init.correlation_id;
const tenant_id = init._tenant_id;

const jobs = batch.map((item, idx) => ({
  ...item,
  tenant_id,
  correlation_id,
  _item_index: idx,
  _priority: item.strategic?.diffusion_type === 'PAID' ? 1 : 5,
  _attempts: 3,
}));

return [{
  json: {
    correlation_id,
    tenant_id,
    batch_size: batch.length,
    source_agent: init.source_agent_header,
    timestamp: init.timestamp,
    jobs,
  }
}];

// ============================================================
// v4 — Construire la réponse 202 Accepted
// ============================================================
// CHANGEMENT vs v3 :
//   v3 : attendait l'ingestion complète pour répondre
//   v4 : répond immédiatement avec correlation_id + info enqueue
// ============================================================

const enqueueResult = $input.first().json;
const prep = $('Préparer enqueue batch').first().json;

return [{
  json: {
    status: 'ACCEPTED',
    correlation_id: prep.correlation_id,
    message: `${prep.batch_size} diffusion(s) enqueued pour traitement asynchrone`,
    payload: {
      batch_size: prep.batch_size,
      source_agent: prep.source_agent,
      queue: 'ingestion',
      job_ids: enqueueResult.job_ids || [],
      enqueued_at: enqueueResult.enqueued_at || new Date().toISOString(),
    },
    _tracking: {
      correlation_id: prep.correlation_id,
      status_endpoint: `/api/v1/diffusions/status/${prep.correlation_id}`,
      dashboard: 'http://localhost:3002/queues',
    },
  }
}];

// Log fire-and-forget (non bloquant)
const prep = $('Préparer enqueue batch').first().json;

return [{
  json: {
    agent: 'ORCHESTRATOR',
    event_type: 'ORCHESTRATION_ENQUEUED',
    message: `Batch de ${prep.batch_size} diffusion(s) enqueued (${prep.source_agent}) → queue:ingestion`,
    job_id: '',
    correlation_id: prep.correlation_id,
    tenant_id: prep.tenant_id,
  }
}];
